def read_pid(pid_path: Path) -> int | None:
    """Return the PID stored at *pid_path* or ``None`` when absent/invalid."""
    if not pid_path.is_file():
        return None
    try:
        return int(pid_path.read_text(encoding="utf-8").strip())
    except (OSError, ValueError):
        return None

